example.code:
# selectors.py — reads only, no side effects
def get_active_users(org_id: int):
    return User.objects.filter(org_id=org_id, is_active=True).select_related("profile")

def get_user_by_email(email: str):
    return User.objects.filter(email=email).first()

# services.py — writes and business logic
def deactivate_user(user_id: int) -> None:
    user = User.objects.get(id=user_id)
    user.is_active = False
    user.save()
    email_service.send_deactivation_notice(user.email)

def create_user_with_profile(email: str, name: str) -> User:
    user = User.objects.create(email=email)
    Profile.objects.create(user=user, name=name)
    email_service.send_welcome(user.email)
    return user

// CreateUserDTO — input contract
class CreateUserDTO {
    public function __construct(
        public string $email,
        public string $name,
        public string $password,
    ) {}
}

// CreateUserAction — business operation
class CreateUserAction {
    public function execute(CreateUserDTO $dto): User {
        $user = User::create([
            'email' => $dto->email,
            'name' => $dto->name,
            'password' => Hash::make($dto->password),
        ]);
        event(new UserCreated($user));
        return $user;
    }
}

// useUserData.js — extracted because used in UserProfile AND UserSettings
function useUserData(userId) {
  const [user, setUser] = React.useState(null);
  const [loading, setLoading] = React.useState(false);
  const [error, setError] = React.useState(null);

  React.useEffect(() => {
    setLoading(true);
    fetch(`/api/users/${userId}`)
      .then(r => r.json())
      .then(u => {
        setUser(u);
        setLoading(false);
      })
      .catch(e => {
        setError(e);
        setLoading(false);
      });
  }, [userId]);

  return { user, loading, error };
}
